configfiles.configfile:
from aoptk.literature.databases.pubmed import PubMed from aoptk.literature.databases.europepmc import EuropePMC from aoptk.literature.databases.pmc import PMC from Bio import Entrez import os
email = os.environ.get("EMAIL")
if "${literature_database}" == "pubmed": Entrez.email = email ids = PubMed("${query}").get_id() elif "${literature_database}" == "europepmc": ids = EuropePMC("${query}").get_id() elif "${literature_database}" == "pmc": ids = PMC("${query}").get_id()
else: raise ValueError("Select valid database.")
with open(f"ids.txt", "w") as f: for id in ids: f.write(f"{id}\n")
